// Pull the three API-shaped sources (by node name) and the trigger payload
const prefs = $('Get Preferences').first().json.data;
const offerings = $('Get Offerings').first().json.data;
const business = $('Get Business').first().json.data;
const wh = $('Webhook').first().json.body;

// Flatten into the exact fields the prompt needs.
// Arrays -> comma strings here, so the prompt node stays simple and unchanged.
return [{
  json: {
    // identifiers carried downstream (needed by the save step)
    calendar_id: wh.calendar_id,
    business_id: wh.business_id,
    month: wh.month,
    year: wh.year,
    // flattened business context for the prompt
    business_name: business.name,
    industry: business.industry,
    brand_tone: prefs.brand_tone,
    pain_points: (prefs.pain_points || []).join(', '),
    offerings: (offerings || []).map(o => o.offering_name).join(', ')
  }
}];

