// Context (calendar_id, month, year) from Merge Context, referenced by name
const ctx = $('Merge Context').first().json;
const calendarId = ctx.calendar_id;
const year = Number(ctx.year);
const month = Number(ctx.month);

// Grab the raw text GPT returned (OpenAI Responses API structure)
let raw;
try {
  raw = $input.first().json.output[0].content[0].text;
} catch (e) {
  throw new Error('Could not find AI response text — OpenAI output structure was unexpected.');
}

// Strip markdown fences if GPT adds them
const cleaned = (raw || '').replace(/```json/gi, '').replace(/```/g, '').trim();

// Parse JSON — fail clearly if GPT returned garbage
let themes;
try {
  themes = JSON.parse(cleaned);
} catch (e) {
  throw new Error('AI did not return valid JSON. Raw start: ' + cleaned.slice(0, 200));
}

// Must be a non-empty array
if (!Array.isArray(themes) || themes.length === 0) {
  throw new Error('AI returned an empty or non-array result.');
}

// Validate + enrich each day with calendar_id and a concrete date (for the save step)
const allowed = ['awareness', 'education', 'promotion', 'trust', 'engagement'];
return themes.map(t => {
  if (t.day == null || !t.theme || !t.objective || !t.post_idea) {
    throw new Error('A day is missing required fields: ' + JSON.stringify(t));
  }
  if (!allowed.includes(t.objective)) t.objective = 'awareness';
  const date = `${year}-${String(month).padStart(2, '0')}-${String(t.day).padStart(2, '0')}`;
  return { json: {
    calendar_id: calendarId,
    date: date,
    day: t.day,
    theme: t.theme,
    objective: t.objective,
    post_idea: t.post_idea
  }};
});

// Collect all the saved days back into one array
const days = $input.all().map(item => item.json);
const ctx = $('Merge Context').first().json;

// Build a single clean summary to return to the caller
return [{
  json: {
    success: true,
    message: "Calendar themes generated and saved",
    calendar_id: ctx.calendar_id,
    days_filled: days.length,
    month: ctx.month,
    year: ctx.year,
    days: days
  }
}];
